import React, { useEffect, useState } from "react";
import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
} from "chart.js";
import { Doughnut, Bar } from "react-chartjs-2";
import "./Dashboard.css";

ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title);

const Dashboard = () => {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const res = await fetch("/api/dashboard-stats");
        const data = await res.json();
        setStats(data);
      } catch (err) {
        console.error("Error loading stats:", err);
      }
    };
    fetchStats();
  }, []);

  if (!stats) return <div className="loading">Loading...</div>;

  const donutOptions = {
    cutout: "80%",
    plugins: {
      legend: { display: false },
      tooltip: { enabled: false },
    },
  };

  const renderDonut = (value, color) => ({
    data: {
      datasets: [
        {
          data: [value, 100 - value],
          backgroundColor: [color, "#e0e0e0"],
          borderWidth: 0,
        },
      ],
    },
  });

  const mainDonutData = {
    labels: ["Free", "Occupied"],
    datasets: [
      {
        data: [stats.pieChart.free, stats.pieChart.occupied],
        backgroundColor: ["#2ecc71", "#e74c3c"],
        borderWidth: 0,
      },
    ],
  };

  const barData = {
    labels: Object.keys(stats.barChart),
    datasets: [
      {
        label: "Free Rooms",
        data: Object.values(stats.barChart),
        backgroundColor: "#2a6bd7",
      },
    ],
  };

  return (
    <div className="dashboard">
      <div className="header">Classroom Availability Dashboard</div>

      <div className="grid-container">
        <div className="card large-card">
          <div className="title">Overall Availability</div>
          <Doughnut data={mainDonutData} options={donutOptions} />
          <div className="donut-center-text">{stats.pieChart.free}</div>
        </div>

        <div className="card">
          <div className="title">Projector Rooms</div>
          <Doughnut data={renderDonut(stats.resources.projectorRooms, "#f1c40f").data} options={donutOptions} />
          <div className="donut-center-text">{stats.resources.projectorRooms}</div>
        </div>

        <div className="card">
          <div className="title">Free Labs</div>
          <Doughnut data={renderDonut(stats.resources.labs, "#fbc02d").data} options={donutOptions} />
          <div className="donut-center-text">{stats.resources.labs}</div>
        </div>

        <div className="card">
          <div className="title">Free Rooms</div>
          <Doughnut data={renderDonut(stats.resources.totalRooms - stats.pieChart.occupied, "#2ecc71").data} options={donutOptions} />
          <div className="donut-center-text">{stats.resources.totalRooms - stats.pieChart.occupied}</div>
        </div>

        <div className="card">
          <div className="title">Occupied Rooms</div>
          <Doughnut data={renderDonut(stats.pieChart.occupied, "#e74c3c").data} options={donutOptions} />
          <div className="donut-center-text">{stats.pieChart.occupied}</div>
        </div>

        <div className="card full-width">
          <div className="title">Free Rooms Per Day</div>
          <Bar
            data={barData}
            options={{
              responsive: true,
              plugins: { legend: { display: false } },
              scales: { y: { beginAtZero: true } },
            }}
          />
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
